import { type Page, expect } from '@playwright/test'

/**
 * Shared E2E test utilities for Kapow.
 *
 * Tagging convention for test titles:
 *
 *   Tiers (pick one):
 *     @critical        — must-pass smoke tests; blocks deployment
 *     @standard        — normal regression coverage
 *     @comprehensive   — edge cases, visual, slow scenarios
 *
 *   Features (pick one or more):
 *     @search    @filters    @pagination   @sorting
 *     @views     @detail     @columns      @geo
 *     @blend     @export     @auth         @nav
 *     @responsive
 *
 *   Example test title:
 *     'loads search page and displays results @critical @search'
 */

/**
 * Navigate to the /search page with the given URL search params.
 *
 * @example
 *   await searchWith(page, { q: 'MIT', state: 'MA' })
 *   // navigates to /search?q=MIT&state=MA
 */
export async function searchWith(
  page: Page,
  params: Record<string, string>,
): Promise<void> {
  const search = new URLSearchParams(params).toString()
  const url = search ? `/search?${search}` : '/search'
  await page.goto(url)
}

/**
 * Wait for the search results skeleton to clear and results to become visible.
 * Asserts that the loading indicator disappears and at least one result or
 * the "institutions found" / "results" text is visible.
 */
export async function waitForResults(page: Page): Promise<void> {
  // Wait for the loading skeleton to disappear
  await expect(page.getByTestId('results-loading')).toBeHidden({
    timeout: 30_000,
  })

  // Wait for the results summary text to appear
  // Matches both "Showing 1-20 of 42 institutions found" and "100+ results"
  await expect(
    page.getByText(/institutions found|results/i),
  ).toBeVisible({ timeout: 10_000 })
}

/**
 * Parse the displayed result count from the results summary text.
 * Handles both "Showing X-Y of Z institutions found" and "100+ results" formats.
 *
 * @returns The total number of results, or 101 for the "100+" display.
 */
export async function getResultCount(page: Page): Promise<number> {
  const summaryLocator = page.getByText(/Showing \d+/i)
  const text = await summaryLocator.textContent()

  if (!text) {
    throw new Error('Could not find results summary text on page')
  }

  // Match "100+ results" format
  const plusMatch = text.match(/(\d+)\+\s*results/i)
  if (plusMatch) {
    return Number(plusMatch[1]) + 1
  }

  // Match "Showing X-Y of Z institutions found" or "Showing X-Y of Z,ZZZ institutions found"
  const ofMatch = text.match(/of\s+([\d,]+)/i)
  if (ofMatch) {
    return Number(ofMatch[1].replace(/,/g, ''))
  }

  throw new Error(`Could not parse result count from text: "${text}"`)
}

import { test, expect } from '@playwright/test'
import { searchWith, waitForResults, getResultCount } from './helpers'

// ── Critical ────────────────────────────────────────────────────────────────

test.describe('Search & Filters — Critical', () => {
  test('home quicksearch navigates to /search with results visible @critical @search', async ({
    page,
  }) => {
    await page.goto('/')

    // Fill the college name field on the home page
    await page.getByPlaceholder('College name…').fill('University')
    await page.getByRole('button', { name: 'Search' }).click()

    // Should navigate to the search page with the query param
    await expect(page).toHaveURL(/\/search\?q=University/)

    // Results should load
    await waitForResults(page)
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)
  })

  test('apply one filter (state) narrows results @critical @filters', async ({ page }) => {
    // Start with an unfiltered search
    await searchWith(page, {})
    await waitForResults(page)
    const unfilteredCount = await getResultCount(page)

    // Apply a state filter via URL (state is a single-enum ChoiceSearchField)
    await searchWith(page, { state: 'MA' })
    await waitForResults(page)
    const filteredCount = await getResultCount(page)

    // Filtered count should be smaller than unfiltered
    expect(filteredCount).toBeLessThan(unfilteredCount)
    expect(filteredCount).toBeGreaterThan(0)
  })
})

// ── Standard ────────────────────────────────────────────────────────────────

test.describe('Search & Filters — Standard', () => {
  test('single-enum filter (state) narrows results and updates URL @standard @filters', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Apply state filter via the sidebar select control
    // The State field is rendered as a <select> (maxSelections === 1)
    const stateSelect = page.locator('label', { has: page.getByText('State') }).locator('select')
    await stateSelect.selectOption('CA')

    // Wait for results to update
    await waitForResults(page)
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)

    // URL should reflect the state filter
    await expect(page).toHaveURL(/[?&]state=CA/)
  })

  test('numeric range filter (enrollment) narrows results @standard @filters', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)
    const unfilteredCount = await getResultCount(page)

    // Apply enrollment range via URL params (NumericalRangeSearchField)
    await searchWith(page, { enrollment: '1000,5000' })
    await waitForResults(page)
    const filteredCount = await getResultCount(page)

    expect(filteredCount).toBeLessThan(unfilteredCount)
    expect(filteredCount).toBeGreaterThan(0)
  })

  test('full-text filter (fields of study) returns matching institutions @standard @filters', async ({
    page,
  }) => {
    // The fields_of_study field is a TextSearchField
    await searchWith(page, { fields_of_study: 'Biology' })
    await waitForResults(page)
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)
  })

  test('clear one filter widens results back @standard @filters', async ({ page }) => {
    // Start with state filter applied
    await searchWith(page, { state: 'MA' })
    await waitForResults(page)
    const filteredCount = await getResultCount(page)

    // Clear the state filter by selecting "Any" in the dropdown
    const stateSelect = page.locator('label', { has: page.getByText('State') }).locator('select')
    await stateSelect.selectOption('')

    await waitForResults(page)
    const clearedCount = await getResultCount(page)

    // After clearing, results should be wider (more results)
    expect(clearedCount).toBeGreaterThan(filteredCount)
  })

  test('combine two filters from different themes reflects AND combination @standard @filters', async ({
    page,
  }) => {
    // Apply state filter alone
    await searchWith(page, { state: 'CA' })
    await waitForResults(page)
    const stateOnlyCount = await getResultCount(page)

    // Apply state + enrollment range (two different themes: LOCATION + ACADEMICS)
    await searchWith(page, { state: 'CA', enrollment: '1000,10000' })
    await waitForResults(page)
    const combinedCount = await getResultCount(page)

    // Combined filters should return fewer results than state alone
    expect(combinedCount).toBeLessThanOrEqual(stateOnlyCount)
    expect(combinedCount).toBeGreaterThan(0)
  })
})

// ── Comprehensive ───────────────────────────────────────────────────────────

test.describe('Search & Filters — Comprehensive', () => {
  test('filter yielding zero results shows empty state with clear button @comprehensive @filters', async ({
    page,
  }) => {
    // Use a name query that is unlikely to match any institution
    await searchWith(page, { q: 'xyzzyplughnotarealnameever12345' })

    // Wait for loading to finish
    await expect(page.getByTestId('results-loading')).toBeHidden({ timeout: 30_000 })

    // Should show "No colleges match your filters" message
    await expect(page.getByText('No colleges match your filters')).toBeVisible()

    // Should have a "Clear all filters" button
    await expect(page.getByRole('button', { name: 'Clear all filters' })).toBeVisible()
  })

  test('clear all filters returns full result set @comprehensive @filters', async ({ page }) => {
    // Start with a restrictive filter that yields zero results
    await searchWith(page, { q: 'xyzzyplughnotarealnameever12345' })
    await expect(page.getByTestId('results-loading')).toBeHidden({ timeout: 30_000 })
    await expect(page.getByText('No colleges match your filters')).toBeVisible()

    // Click "Clear all filters"
    await page.getByRole('button', { name: 'Clear all filters' }).click()

    // Should return to showing results
    await waitForResults(page)
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)

    // URL should be clean (no filter params)
    await expect(page).toHaveURL('/search')
  })

  test('filter state is reflected in URL query params @comprehensive @filters', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Apply state filter via sidebar
    const stateSelect = page.locator('label', { has: page.getByText('State') }).locator('select')
    await stateSelect.selectOption('NY')
    await waitForResults(page)

    // Verify URL contains the state param
    await expect(page).toHaveURL(/[?&]state=NY/)

    // Apply a name filter via the sidebar text input
    const nameInput = page.getByRole('textbox', { name: 'Name' })
    await nameInput.fill('College')

    // Wait for debounced update (400ms debounce + network)
    await page.waitForTimeout(600)
    await waitForResults(page)

    // Both params should be in the URL
    await expect(page).toHaveURL(/[?&]state=NY/)
    await expect(page).toHaveURL(/[?&]name=College/)
  })

  test('rapid filter changes do not cause stale or inconsistent results @comprehensive @filters', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Rapidly change state filters
    const stateSelect = page.locator('label', { has: page.getByText('State') }).locator('select')
    await stateSelect.selectOption('CA')
    await stateSelect.selectOption('NY')
    await stateSelect.selectOption('TX')

    // Wait for the final results to settle
    await waitForResults(page)

    // URL should reflect only the last selection
    await expect(page).toHaveURL(/[?&]state=TX/)

    // Results should be valid (not zero unless TX genuinely has zero)
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)
  })
})

import { test, expect } from '@playwright/test'
