import { test, expect } from '@playwright/test'
import { searchWith, waitForResults, getResultCount } from './helpers'

/**
 * Product Contract Acceptance Suite
 *
 * Each test maps directly to an acceptance criterion from
 * contracts/product-contracts.json. Tests are tagged @acceptance @critical
 * so they can be run as a gate via: pnpm exec playwright test --grep @acceptance
 *
 * Contract → test mapping is documented in docs/contracts/product.md.
 */

// ── Contract: institution-search ─────────────────────────────────────────────

test.describe('Contract: institution-search', () => {
  test('AC1: text search returns results @acceptance @critical @search', async ({
    page,
  }) => {
    await searchWith(page, { q: 'University' })
    await waitForResults(page)
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)
  })

  test('AC2: filters available for all 11 themes in sidebar @acceptance @critical @search', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // The sidebar should contain filter group headings for each active theme.
    // These match the theme labels from the search field registry.
    const expectedThemes = [
      'Core',
      'Location',
      'Academics',
      'Cost & Financial Aid',
      'Outcomes',
      'Rankings',
      'Admissions',
      'Athletics',
      'Fields of Study',
      'Cultural Environment',
      'Weather & Climate',
    ]

    for (const theme of expectedThemes) {
      await expect(
        page.getByRole('heading', { name: theme, exact: true }).or(
          page.getByText(theme, { exact: true }),
        ),
      ).toBeVisible({ timeout: 5_000 })
    }
  })

  test('AC3: results can be sorted by a sortable field @acceptance @critical @sorting', async ({
    page,
  }) => {
    await searchWith(page, { view: 'table' })
    await waitForResults(page)

    // Click the Name sort header
    const sortButton = page.getByTestId('sort-name')
    await expect(sortButton).toBeVisible()
    await sortButton.click()
    await waitForResults(page)

    // URL should reflect the sort state
    await expect(page).toHaveURL(/[?&]sort=name/)
  })

  test('AC4: geographic search filters by radius @acceptance @critical @geo', async ({
    page,
  }) => {
    // Search with location params and verify distance appears
    await searchWith(page, {
      userLat: '42.33',
      userLng: '-71.11',
      userState: 'MA',
    })
    await waitForResults(page)

    // Distance badges should appear on results
    const distanceBadges = page.getByTestId('distance')
    await expect(distanceBadges.first()).toBeVisible({ timeout: 10_000 })
  })

  test('AC5: pagination supports configurable page sizes @acceptance @critical @pagination', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Change page size
    const pageSizeSelect = page.getByLabel('Per page')
    await pageSizeSelect.selectOption('5')
    await waitForResults(page)

    // URL should reflect page size
    const url = page.url()
    expect(url).toContain('pageSize=5')

    // Summary should show at most 5 results in the range
    const summary = await page.getByText(/Showing \d+[–-]\d+ of/i).textContent()
    const rangeMatch = summary!.match(/Showing (\d+)[–-](\d+)/)
    expect(rangeMatch).not.toBeNull()
    const rangeSize = Number(rangeMatch![2]) - Number(rangeMatch![1]) + 1
    expect(rangeSize).toBeLessThanOrEqual(5)
  })

  test('AC6: sort and filter state encoded in URL for shareability @acceptance @critical @search', async ({
    page,
  }) => {
    // Apply filter + sort via URL, verify they persist
    await searchWith(page, { state: 'CA', sort: 'name', view: 'table' })
    await waitForResults(page)

    // Verify URL contains both filter and sort
    const url = page.url()
    expect(url).toContain('state=CA')
    expect(url).toContain('sort=name')

    // Navigate to the same URL fresh — state should be preserved
    await page.goto(url)
    await waitForResults(page)
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)

    // URL should still have the params
    await expect(page).toHaveURL(/state=CA/)
    await expect(page).toHaveURL(/sort=name/)
  })
})

// ── Contract: csv-export ─────────────────────────────────────────────────────

test.describe('Contract: csv-export', () => {
  test('AC1: CSV download includes all exportable fields @acceptance @critical @export', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    const downloadPromise = page.waitForEvent('download')
    const csvButton = page.getByRole('button', { name: /Export CSV/i })
    await expect(csvButton).toBeEnabled()
    await csvButton.click()

    const download = await downloadPromise
    expect(download.suggestedFilename()).toContain('.csv')
  })

  test('AC2: active filters applied to exported data @acceptance @critical @export', async ({
    page,
  }) => {
    await searchWith(page, { state: 'MA' })
    await waitForResults(page)

    const downloadPromise = page.waitForEvent('download')
    await page.getByRole('button', { name: /Export CSV/i }).click()

