    const text = await distanceBadges.first().textContent()
    expect(text).toMatch(/(<\s*1\s*mi|\d[\d,]*\s*mi|\u2014)/)
  })

  test('AC4: results can be sorted by distance from home @acceptance @critical @sorting', async ({
    page,
  }) => {
    await searchWith(page, {
      userLat: '42.33',
      userLng: '-71.11',
      userState: 'MA',
      view: 'table',
    })
    await waitForResults(page)

    // Sort by distance header should be available
    const sortDistance = page.getByTestId('sort-distance')
    await expect(sortDistance).toBeVisible()

    await sortDistance.click()
    await waitForResults(page)

    await expect(page).toHaveURL(/sort=distance/)
  })
})

// ── Contract: similar-institutions ───────────────────────────────────────────

test.describe('Contract: similar-institutions', () => {
  test('AC1: similar institutions shown in detail view @acceptance @critical @detail', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Open the first institution detail
    const firstCard = page
      .locator('[class*="mantine-Card-root"][role="button"]')
      .first()
    await firstCard.click()

    const modal = page.locator(
      '[role="dialog"][aria-label="Institution details"]',
    )
    await expect(modal).toBeVisible({ timeout: 10_000 })

    // Wait for data to load
    await expect(modal.locator('[class*="mantine-Loader"]')).toBeHidden({
      timeout: 10_000,
    })

    // Click "Find Similar Schools"
    const similarButton = modal.getByRole('button', {
      name: 'Find Similar Schools',
    })
    await expect(similarButton).toBeVisible()
    await similarButton.click()

    // "Similar Schools" heading should appear
    await expect(modal.getByText('Similar Schools')).toBeVisible({
      timeout: 10_000,
    })
  })

  test('AC2: at least 5 similar institutions returned @acceptance @critical @detail', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    const firstCard = page
      .locator('[class*="mantine-Card-root"][role="button"]')
      .first()
    await firstCard.click()

    const modal = page.locator(
      '[role="dialog"][aria-label="Institution details"]',
    )
    await expect(modal).toBeVisible({ timeout: 10_000 })
    await expect(modal.locator('[class*="mantine-Loader"]')).toBeHidden({
      timeout: 10_000,
    })

    await modal.getByRole('button', { name: 'Find Similar Schools' }).click()
    await expect(modal.getByText('Similar Schools')).toBeVisible({
      timeout: 10_000,
    })

    // Count similar institution cards
    const similarCards = modal.locator(
      '[class*="mantine-Card-root"]:not([role="button"])',
    )
    const noSimilarMsg = modal.getByText('No similar institutions found.')

    // Either we have cards or the institution has no similar matches
    const hasCards = await similarCards.first().isVisible().catch(() => false)
    const hasNoMsg = await noSimilarMsg.isVisible().catch(() => false)

    if (hasCards) {
      const cardCount = await similarCards.count()
      expect(cardCount).toBeGreaterThanOrEqual(5)
    } else {
      // If no similar institutions, that's acceptable for some institutions
      expect(hasNoMsg).toBe(true)
    }
  })
})

// ── Contract: map-view ───────────────────────────────────────────────────────

test.describe('Contract: map-view', () => {
  test('AC1: map view selectable via view toggle @acceptance @critical @views', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Switch to map view
    await page.locator('input[value="map"] + label').click()

    // Leaflet map container should be visible
    const mapContainer = page.locator('.leaflet-container')
    await expect(mapContainer).toBeVisible({ timeout: 10_000 })
  })

  test('AC2: map shows markers for results @acceptance @critical @views', async ({
    page,
  }) => {
    await searchWith(page, { view: 'map' })
    await waitForResults(page)

    const mapContainer = page.locator('.leaflet-container')
    await expect(mapContainer).toBeVisible({ timeout: 10_000 })

    // Map should have markers (Leaflet renders them as .leaflet-marker-icon)
    const markers = mapContainer.locator('.leaflet-marker-icon')
    await expect(markers.first()).toBeVisible({ timeout: 15_000 })
    const markerCount = await markers.count()
    expect(markerCount).toBeGreaterThan(0)
  })

  test('AC3: map respects active search filters @acceptance @critical @views', async ({
    page,
  }) => {
    // Apply a state filter and verify map shows results
    await searchWith(page, { state: 'MA', view: 'map' })
    await waitForResults(page)

    const mapContainer = page.locator('.leaflet-container')
    await expect(mapContainer).toBeVisible({ timeout: 10_000 })

    // Should still have markers (MA has institutions)
    const markers = mapContainer.locator('.leaflet-marker-icon')
    await expect(markers.first()).toBeVisible({ timeout: 15_000 })
  })

  test('AC4: view mode persists in localStorage @acceptance @critical @views', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Switch to table view
    await page.locator('input[value="table"] + label').click()
    await expect(page.locator('table')).toBeVisible({ timeout: 10_000 })

    // Check localStorage
    const storedView = await page.evaluate(() =>
      localStorage.getItem('kapow:results-view'),
    )
    expect(storedView).toBe('table')

    // Reload without view param — should restore from localStorage
    await page.goto('/search')
    await waitForResults(page)
    await expect(page.locator('table')).toBeVisible({ timeout: 10_000 })
  })
})

